  tax REAL DEFAULT 0,
  shipping REAL DEFAULT 0,
  total REAL NOT NULL,
  notes TEXT,
  created_at INTEGER DEFAULT (unixepoch()),
  updated_at INTEGER DEFAULT (unixepoch())
, customer_phone TEXT, courier_provider text, courier_consignment_id text, courier_status text, payment_method TEXT DEFAULT 'cod', transaction_id TEXT, manual_payment_details TEXT, review_request_sent integer DEFAULT 0, review_request_sent_at integer, idempotency_key TEXT, `landing_page_id` integer REFERENCES saved_landing_configs(id), `utm_source` text, `utm_medium` text, `utm_campaign` text);
