INSERT INTO "builder_sections" VALUES('RCZIpYDypWHIn-0p1PS4A','qN7rN_IjpheUZhRzACo6l','cta',1,7,'{"headline":"অফার শেষ হতে আর অল্প সময় বাকি!","subheadline":"নিচের ফর্মটি পূরণ করে এখনই অর্ডার করুন","buttonText":"অর্ডার কনফার্ম করুন","template":"minimal","productPrice":1990,"discountedPrice":1490,"insideDhakaCharge":60,"outsideDhakaCharge":120,"enableFreeShipping":false,"freeShippingThreshold":2000,"freeShippingMessage":"৳{remaining} আরো কিনলে ফ্রি ডেলিভারি!","enableCodSurcharge":false,"codSurchargeAmount":50,"variants":[{"id":"1","name":"১ পিস","price":1490},{"id":"2","name":"২ পিস (সেভ ৳২০০)","price":2780},{"id":"3","name":"৩ পিস (সেভ ৳৫০০)","price":3970}],"variantLabel":"প্যাকেজ নির্বাচন করুন","phonePlaceholder":"আপনার মোবাইল নম্বর","addressPlaceholder":"বাসা নম্বর, রোড, এলাকা","quantityLabel":"পরিমাণ","insideDhakaLabel":"ঢাকার ভিতরে","outsideDhakaLabel":"ঢাকার বাইরে","subtotalLabel":"সাবটোটাল","deliveryLabel":"ডেলিভারি চার্জ","totalLabel":"সর্বমোট","showDistrictField":true,"showUpazilaField":true,"districtLabel":"জেলা","upazilaLabel":"উপজেলা/থানা","addressLabel":"বিস্তারিত ঠিকানা","districtPlaceholder":"জেলা নির্বাচন করুন","upazilaPlaceholder":"উপজেলা নির্বাচন করুন","shippingZoneMode":"auto","showEmailField":false,"showAltPhoneField":false,"showNoteField":true,"nameLabel":"আপনার নাম","namePlaceholder":"আপনার নাম লিখুন","emailLabel":"ইমেইল","emailPlaceholder":"আপনার ইমেইল (ঐচ্ছিক)","altPhoneLabel":"বিকল্প ফোন","altPhonePlaceholder":"বিকল্প মোবাইল নম্বর","noteLabel":"অর্ডার নোট","notePlaceholder":"অতিরিক্ত তথ্য/নির্দেশনা (ঐচ্ছিক)","thankYouHeadline":"অর্ডার সফল হয়েছে! 🎉","thankYouMessage":"ধন্যবাদ! আমরা শীঘ্রই আপনার সাথে যোগাযোগ করবো।","showOrderDetails":true,"showWhatsAppButton":false,"showTrustBadges":true,"codLabel":"ক্যাশ অন ডেলিভারি","secureLabel":"১০০% সিকিউর অর্ডার"}',1,1768747424,1768747424,NULL,NULL,NULL);
CREATE TABLE advanced_builder_pages (id text PRIMARY KEY NOT NULL, store_id integer NOT NULL, slug text NOT NULL, title text, product_id integer, status text DEFAULT 'draft', published_at integer, last_published_at integer, template_id text, seo_title text, seo_description text, og_image text, view_count integer DEFAULT 0, order_count integer DEFAULT 0, created_at integer, updated_at integer, FOREIGN KEY (store_id) REFERENCES stores(id) ON DELETE cascade, FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE NO ACTION);
CREATE TABLE advanced_builder_sections (id text PRIMARY KEY NOT NULL, page_id text NOT NULL, type text NOT NULL, enabled integer DEFAULT 1 NOT NULL, sort_order integer NOT NULL, props_json text DEFAULT '{}' NOT NULL, blocks_json text DEFAULT '[]' NOT NULL, published_props_json text, published_blocks_json text, published_at integer, version integer DEFAULT 1 NOT NULL, created_at integer, updated_at integer, FOREIGN KEY (page_id) REFERENCES advanced_builder_pages(id) ON DELETE cascade);
CREATE TABLE IF NOT EXISTS "leads_data" (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`conversation_id` integer NOT NULL,
	`key` text NOT NULL,
	`value` text NOT NULL,
	`created_at` integer,
	FOREIGN KEY (`conversation_id`) REFERENCES `ai_conversations`(`id`) ON UPDATE no action ON DELETE cascade
);
CREATE TABLE IF NOT EXISTS "messages" (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`conversation_id` integer NOT NULL,
	`role` text NOT NULL,
	`content` text NOT NULL,
	`function_name` text,
	`function_args` text,
	`function_result` text,
	`tokens_used` integer,
	`credits_used` integer DEFAULT 1,
	`created_at` integer,
	FOREIGN KEY (`conversation_id`) REFERENCES `ai_conversations`(`id`) ON UPDATE no action ON DELETE cascade
);
CREATE TABLE `product_recommendations` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`store_id` integer NOT NULL,
	`source_product_id` integer NOT NULL,
	`recommended_product_id` integer NOT NULL,
	`score` real DEFAULT 0,
	`reason` text DEFAULT 'similar_category',
	`created_at` integer,
	FOREIGN KEY (`store_id`) REFERENCES `stores`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`source_product_id`) REFERENCES `products`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`recommended_product_id`) REFERENCES `products`(`id`) ON UPDATE no action ON DELETE cascade
);
CREATE TABLE IF NOT EXISTS "ab_tests" (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`store_id` integer NOT NULL,
	`name` text NOT NULL,
	`test_key` text NOT NULL,
	`variant_a` text NOT NULL,
	`variant_b` text NOT NULL,
	`traffic_split` integer DEFAULT 50,
	`status` text DEFAULT 'active',
	`views_a` integer DEFAULT 0,
	`conversions_a` integer DEFAULT 0,
	`views_b` integer DEFAULT 0,
	`conversions_b` integer DEFAULT 0,
	`winner` text,
	`started_at` integer,
	`ended_at` integer,
	`created_at` integer,
	FOREIGN KEY (`store_id`) REFERENCES `stores`(`id`) ON UPDATE no action ON DELETE cascade
);
CREATE TABLE `published_pages` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`store_id` integer NOT NULL,
	`page_type` text DEFAULT 'landing',
	`product_id` integer,
	`html_content` text NOT NULL,
	`css_content` text,
	`meta_tags` text,
	`template_id` text,
	`config_hash` text,
	`published_at` integer,
	`expires_at` integer,
	`created_at` integer,
	`updated_at` integer,
	FOREIGN KEY (`store_id`) REFERENCES `stores`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`product_id`) REFERENCES `products`(`id`) ON UPDATE no action ON DELETE no action
);
CREATE TABLE `page_versions` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`store_id` integer NOT NULL,
	`config_json` text NOT NULL,
	`version_label` text,
	`created_by` integer,
	`published_at` integer,
	`created_at` integer,
	FOREIGN KEY (`store_id`) REFERENCES `stores`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`created_by`) REFERENCES `users`(`id`) ON UPDATE no action ON DELETE no action
);
CREATE TABLE `template_analytics` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`store_id` integer NOT NULL,
	`template_id` text NOT NULL,
	`page_views` integer DEFAULT 0,
	`unique_visitors` integer DEFAULT 0,
	`orders_generated` integer DEFAULT 0,
	`revenue_generated` real DEFAULT 0,
	`conversion_rate` real DEFAULT 0,
	`period_start` integer,
	`period_end` integer,
	`updated_at` integer,
	`created_at` integer,
	FOREIGN KEY (`store_id`) REFERENCES `stores`(`id`) ON UPDATE no action ON DELETE cascade
);
